mapper.select:
SELECT EXISTS (
  SELECT 1
    FROM role_actions ra
    JOIN screen_actions sa ON sa.action_id = ra.action_id
    JOIN screens s         ON s.screen_id  = sa.screen_id
   WHERE ra.role_key   = #{roleKey}
     AND s.screen_key  = #{screenKey}
     AND sa.action_key = #{actionKey}
     AND sa.use_yn = TRUE
     AND s.use_yn  = TRUE
)
